<?php
namespace App\Http\Controllers\Api\Internal;
use App\Http\Controllers\Controller;use App\Services\Audit\AuditLogger;use App\Services\Dashboard\DashboardAnalyticsService;use Illuminate\Http\Request;
class DashboardApiController extends Controller { public function indicators(Request $request, DashboardAnalyticsService $svc, AuditLogger $audit){ $filters=$request->only(['quality_status','region_id','kbli_id','legality_status','period_id']); $audit->log('dashboard.indicators.access',$request,'dashboard'); return response()->json(['data'=>$svc->indicators($filters)]); } public function charts(Request $request, DashboardAnalyticsService $svc){ $filters=$request->only(['quality_status','region_id','kbli_id','legality_status','period_id']); return response()->json(['data'=>['kbli_composition'=>$svc->kbliComposition($filters),'legality_status'=>$svc->legalityStatus($filters),'performance_trend'=>$svc->performanceTrend($filters)]]); } public function map(Request $request, DashboardAnalyticsService $svc){ return response()->json(['data'=>['aggregate_points'=>$svc->mapAggregate($request->all())]]); } public function summaryTable(Request $request, DashboardAnalyticsService $svc){ $page=max(1,(int)$request->query('page',1)); $perPage=min(50,max(10,(int)$request->query('per_page',20))); $table=$svc->summaryTable($request->all(),$perPage); return response()->json(['data'=>$table->items(),'meta'=>['page'=>$page,'per_page'=>$perPage,'total'=>$table->total()]]); }}
